import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { SeedService } from '../../data/seed.service';

interface TimelineItem { type: string; date: string; summary: string; }

@Component({
  selector: 'app-contact-detail',
  standalone: true,
  imports: [CommonModule, RouterLink],
  templateUrl: './contact-detail.component.html',
  styleUrl: './contact-detail.component.css',
})
export class ContactDetailComponent {
  id: string;
  today = new Date('2026-07-10');
  tabs = ['timeline', 'notes', 'signals', 'hospitality'];
  activeTab = signal('timeline');

  contact = computed(() => this.seed.contactById(this.id));
  account = computed(() => {
    const c = this.contact();
    return c ? this.seed.accountById(c.accountId) : undefined;
  });

  signalEmails = computed(() => {
    const c = this.contact();
    if (!c) return [];
    return this.seed.emails().filter((e) => e.from === c.name);
  });

  reconnectNeeded = computed(() => {
    const c = this.contact();
    return c ? this.daysSince(c.lastTouch) > 30 : false;
  });

  // presentation-only interaction timeline
  timeline: TimelineItem[] = [
    { type: 'Email', date: '2026-07-06', summary: 'Confirmed Volition Canyon submittal schedule; positive tone.' },
    { type: 'Call', date: '2026-06-24', summary: '20-min check-in on data hall B expansion timing.' },
    { type: 'Meeting', date: '2026-06-11', summary: 'On-site walkthrough with facilities team; lineup reviewed.' },
    { type: 'Email', date: '2026-05-28', summary: 'Shared budgetary pricing for E6.2 4000A breakers.' },
    { type: 'Call', date: '2026-05-09', summary: 'Intro call — mapped decision process and champions.' },
  ];

  daysSince(iso: string): number {
    const then = new Date(iso).getTime();
    return Math.round((this.today.getTime() - then) / 86400000);
  }

  typeBadge(type: string): string {
    switch (type) {
      case 'Email': return 'badge-info';
      case 'Call': return 'badge-success';
      case 'Meeting': return 'badge-warning';
      default: return 'badge-neutral';
    }
  }

  setTab(tab: string): void {
    this.router.navigate([], { queryParams: { tab }, queryParamsHandling: 'merge' });
  }

  constructor(public seed: SeedService, private route: ActivatedRoute, private router: Router) {
    this.id = this.route.snapshot.paramMap.get('id') ?? '';
    const t = this.route.snapshot.queryParamMap.get('tab');
    this.activeTab.set(t && this.tabs.includes(t) ? t : 'timeline');
    this.route.queryParamMap.subscribe((q) => {
      const tab = q.get('tab');
      this.activeTab.set(tab && this.tabs.includes(tab) ? tab : 'timeline');
    });
  }
}
